function calculate(expression: string): number {
  if (expression.includes('+')) {
    return parseInt(expression.split('+')[0]) + parseInt(expression.split('+')[1]);
  } else if (expression.includes('-')) {
    return parseInt(expression.split('-')[0]) - parseInt(expression.split('-')[1]);
  } else if (expression.includes('*')) {
    return parseInt(expression.split('*')[0]) * parseInt(expression.split('*')[1]);
  } else if (expression.includes('/')) {
    return parseInt(expression.split('/')[0]) / parseInt(expression.split('/')[1]);
  }
  return 0;
}

